THE CLAIM:
{
 "title": "Germany hyperscale-owned share is far below the 44% we assumed",
 "narrative": "The model spreads Synergy's global 48% hyperscale share flat onto Central Europe. But about 60% of Europe's hyperscaler self-build sits in Ireland, the Netherlands, Sweden and Belgium, three of which are outside CE-7. So the implied German hyperscale cell, roughly 22% of the market, mostly does not exist as hyperscale-owned sites, and the Year-1 beachhead is much smaller.",
 "mechanism": [
  {
   "step": "trigger",
   "text": "Synergy's 48% hyperscale share is global, not regional.",
   "refs": [
    "digest:seg-mix#c0",
    "digest:seg-mix#c14",
    "ledger:seg.hyperscale"
   ]
  },
  {
   "step": "propagation",
   "text": "In CE-7 hyperscale demand is leased, counted twice with colo.",
   "refs": [
    "digest:seg-mix#c13",
    "digest:geo-region-denominator#c7",
    "digest:geo-region-denominator#c9"
   ]
  },
  {
   "step": "model-impact",
   "text": "Real buyer is the colo operator, needing colo-grade product.",
   "refs": [
    "ledger:seg.hyperscale",
    "ledger:seg.colocation",
    "profile:Who is the primary buyer you'll sell through first?"
   ]
  }
 ],
 "falsifier": "A Europe- or CE-scoped split from Synergy, CBRE or JLL showing hyperscale-owned capacity at 40% or more of CE-7 total.",
 "category": "model-structure",
 "evidence": [
  {
   "title": "CBRE: European hyperscaler self-build capacity growth to outpace colocation supply growth",
   "sourceType": "industry-report",
   "publisher": "DatacenterDynamics (citing CBRE)",
   "date": "2026-02-20",
   "excerpt": "This new supply will be delivered across nine European countries, with 60 percent of Europe’s operational hyperscale self-build capacity located in Ireland, the Netherlands, Sweden, and Belgium.",
   "url": "https://www.datacenterdynamics.com/en/news/cbre-european-hyperscaler-self-build-capacity-growth-to-outpace-colocation-supply-growth-but-supply-outpaces-take-up-in-weaker-than-expected-2025/",
   "attached": true
  },
  {
   "title": "On-Premise Data Center Capacity Being Increasingly Dwarfed by Hyperscalers and Colocation Companies",
   "sourceType": "analyst-estimate",
   "publisher": "Synergy Research Group",
   "date": "2023-07-12",
   "excerpt": "Approximately half of that hyperscale capacity is in own-built, owned data centers and half is in leased facilities.",
   "url": "https://www.srgresearch.com/articles/on-premise-data-center-capacity-being-increasingly-dwarfed-by-hyperscalers-and-colocation-companies",
   "attached": true
  },
  {
   "title": "Frankfurt DCI Report 2024: Data Centre Colocation, Hyperscale Cloud & Interconnection",
   "sourceType": "industry-report",
   "publisher": "Structure Research",
   "date": "2024-06-24",
   "excerpt": "Hyperscale colocation is growing at a five-year CAGR of 26.1% and retail colocation is moving along at a 10.3% clip.",
   "url": "https://www.structureresearch.net/product/frankfurt-dci-report-2024-data-centre-colocation-hyperscale-cloud-interconnection/",
   "attached": true
  }
 ]
}

THE LEDGER FACTS IT TARGETS (current values, derivations, bands):
[
 {
  "id": "seg.hyperscale",
  "label": "Hyperscale",
  "kind": "estimated",
  "value": 0.44,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "triangulated",
  "dimension": "segment",
  "dimensionValue": "hyperscale",
  "sensitivityRange": {
   "low": 0.4,
   "high": 0.48
  },
  "funnelActive": true,
  "derivation": {
   "method": "Capacity-split rescaling",
   "expression": "Synergy end-2025 hyperscale 48% × 0.91 (edge+telecom carve-out) = 0.44",
   "crossCheck": "Synergy Q1-2025 vintage: 44% — brackets the band"
  },
  "provenance": {
   "rationale": "Multiple Synergy vintages (41→48% through 2025) agree on trajectory; global split applied to CE → inferred.",
   "promotionPath": "Replace with a Europe-scoped capacity split when CBRE/Synergy publish one."
  },
  "evidence": [
   {
    "title": "Hyperscale operators to account for 67% of all data center capacity by 2031",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2026",
    "excerpt": "They now account for 48% of the worldwide capacity of all data centers... non-hyperscale colocation capacity accounting for another 20%... leaves enterprise on-premise data centers with just 32%.",
    "attached": true
   },
   {
    "title": "Hyperscale operators and colocation continue to drive huge changes",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2025-06-24",
    "excerpt": "They now account for 44% of the worldwide capacity of all data centers (Q1 2025 vintage).",
    "attached": true
   }
  ]
 },
 {
  "id": "seg.colocation",
  "label": "Colocation",
  "kind": "estimated",
  "value": 0.18,
  "unit": "ratio",
  "confidence": "inferred",
  "maturity": "single-source",
  "dimension": "segment",
  "dimensionValue": "colocation",
  "sensitivityRange": null,
  "funnelActive": true,
  "derivation": {
   "method": "Capacity-split rescaling",
   "expression": "Synergy end-2025 non-hyperscale colocation 20% × 0.91 = 0.18"
  },
  "provenance": {
   "rationale": "Single publisher's capacity series (20–22% across vintages), global scope applied to CE → inferred."
  },
  "evidence": [
   {
    "title": "Hyperscale operators to account for 67% of all data center capacity by 2031",
    "sourceType": "industry-report",
    "publisher": "Synergy Research Group",
    "date": "2026",
    "excerpt": "Non-hyperscale colocation capacity accounting for another 20% of total capacity (end-2025).",
    "attached": true
   }
  ]
 }
]

Emit JSON: { resolution: "error"|"risk", settleTest, proposedCorrection: {nodeId, value, low, high, rationale} or null, researchQueries: [{query, kind}] ([] for risks) }
